// ddxSidecarFile is the YAML structure of a .ddx.yaml sidecar file.
type ddxSidecarFile struct {
	DDx ddxSidecarMeta `yaml:"ddx"`
}

type ddxSidecarMeta struct {
	ID          string          `yaml:"id"`
	Title       string          `yaml:"title"`
	MediaType   string          `yaml:"media_type"`
	Description string          `yaml:"description"`
	GeneratedBy *ddxGeneratedBy `yaml:"generated_by"`
}

type ddxGeneratedBy struct {
	RunID         string `yaml:"run_id"`
	PromptSummary string `yaml:"prompt_summary"`
	SourceHash    string `yaml:"source_hash"`
}

// Artifacts is the resolver for the artifacts query.
// It returns a paginated, optionally-filtered list of DDx-tracked artifacts
// for the given project. Documents come from the FEAT-007 doc graph; other
// artifacts come from .ddx.yaml sidecar files found under .ddx/plugins/.
func (r *queryResolver) Artifacts(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, mediaType *string, search *string, sortKey *ArtifactSort, staleness *string, phase *string, prefix []string) (*ArtifactConnection, error) {
	root := r.projectRoot(ctx, projectID)

	artifacts, err := collectArtifacts(root)
	if err != nil {
		return nil, fmt.Errorf("collecting artifacts: %w", err)
	}

	// Apply mediaType filter (supports X/* wildcard suffix).
	if mediaType != nil && *mediaType != "" {
		mt := *mediaType
		filtered := artifacts[:0]
		if strings.HasSuffix(mt, "/*") {
			prefix := strings.TrimSuffix(mt, "*") // keep trailing slash
			for _, a := range artifacts {
				if strings.HasPrefix(a.MediaType, prefix) {
					filtered = append(filtered, a)
				}
			}
		} else {
			for _, a := range artifacts {
				if a.MediaType == mt {
					filtered = append(filtered, a)
				}
			}
		}
		artifacts = filtered
	}

	// Apply staleness filter.
	if staleness != nil && *staleness != "" {
		st := *staleness
		filtered := artifacts[:0]
		for _, a := range artifacts {
			if a.Staleness == st {
				filtered = append(filtered, a)
			}
		}
		artifacts = filtered
	}

	// Apply phase filter: matches when path is under docs/helix/<phase>/
	// where <phase> is either an exact match (e.g. "01-frame") or a numeric
	// prefix (e.g. "01") matching docs/helix/01-*/.
	if phase != nil && *phase != "" {
		ph := *phase
		filtered := artifacts[:0]
		for _, a := range artifacts {
			if matchesPhase(a.Path, ph) {
				filtered = append(filtered, a)
			}
		}
		artifacts = filtered
	}

	// Apply prefix filter (multi-value OR over id-prefix segments,
	// e.g. ADR, SD, FEAT, US, RSCH).
	if len(prefix) > 0 {
		set := make(map[string]struct{}, len(prefix))
		for _, p := range prefix {
			if p != "" {
				set[strings.ToUpper(p)] = struct{}{}
			}
		}
		if len(set) > 0 {
			filtered := artifacts[:0]
			for _, a := range artifacts {
				if _, ok := set[idPrefixSegment(a.ID)]; ok {
					filtered = append(filtered, a)
				}
			}
			artifacts = filtered
		}
	}

	// Apply search filter across title, path, description, frontmatter, and
	// body text per TD-029 precedence. Matches are recorded so each edge can
	// surface a context-window snippet on ArtifactEdge.snippet.
	matchSnippets := map[string]string{}
	if search != nil && *search != "" {
		q := strings.ToLower(*search)
		filtered := artifacts[:0]
		for _, a := range artifacts {
			snippet, ok := matchArtifactForSearch(a, root, q)
			if ok {
				filtered = append(filtered, a)
				matchSnippets[a.ID] = snippet
			}
		}
		artifacts = filtered
	}

	if err := attachArtifactTypeDefinitionsToArtifacts(root, artifacts); err != nil {
		return nil, fmt.Errorf("loading artifact type definitions: %w", err)
	}

	// Sort with (sortKey, id) tie-breaker for stable cursor pagination.
	sortArtifacts(artifacts, sortKey)

	// Build Relay edges.
	all := make([]*ArtifactEdge, len(artifacts))
	for i, a := range artifacts {
		cp := a
		edge := &ArtifactEdge{
			Node:   cp,
			Cursor: encodeStableCursor(cp.ID),
		}
		if sn, ok := matchSnippets[cp.ID]; ok && sn != "" {
			s := sn
			edge.Snippet = &s
		}
		all[i] = edge
	}

	startIdx := 0
	if after != nil {
		if afterID, ok := decodeStableCursor(*after); ok {
			for i, e := range all {
				if e.Node.ID == afterID {
					startIdx = i + 1
					break
				}
			}
		}
	}
	endIdx := len(all)
	if before != nil {
		if beforeID, ok := decodeStableCursor(*before); ok {
			for i, e := range all {
				if e.Node.ID == beforeID {
					endIdx = i
					break
				}
			}
		}
	}
	if startIdx > endIdx {
		startIdx = endIdx
	}

	windowSize := endIdx - startIdx
	slice := all[startIdx:endIdx]
	if first != nil && *first >= 0 && *first < len(slice) {
		slice = slice[:*first]
	}
	if last != nil && *last >= 0 && *last < len(slice) {
		slice = slice[len(slice)-*last:]
	}

	pageInfo := &PageInfo{
		HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
		HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
	}
	if len(slice) > 0 {
		pageInfo.StartCursor = &slice[0].Cursor
		pageInfo.EndCursor = &slice[len(slice)-1].Cursor
	}

	return &ArtifactConnection{
		Edges:      slice,
		PageInfo:   pageInfo,
		TotalCount: len(all),
	}, nil
}

// sortArtifacts orders artifacts by the requested sort key with a stable
// (sortKey, id) tie-breaker so cursor pagination is deterministic across
// pages even when the primary key has duplicate values.
func sortArtifacts(artifacts []*Artifact, key *ArtifactSort) {

package graphql

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/artifacttypes"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
)

const artifactTypeFileCapBytes = 64 * 1024

var artifactTypeLoader = artifacttypes.NewLoader()

func artifactTypeDefinitionsForPath(workingDir, artifactPath string) ([]*ArtifactTypeDefinition, error) {
	prefix := prefixOf(artifactPath)
	if prefix == "" {
		return []*ArtifactTypeDefinition{}, nil
	}
	if workingDir == "" {
		return []*ArtifactTypeDefinition{}, nil
	}

	cfg, err := config.LoadWithWorkingDir(workingDir)
	if err != nil {
		return nil, fmt.Errorf("loading config: %w", err)
	}
	if cfg.Library == nil || strings.TrimSpace(cfg.Library.Path) == "" {
		return []*ArtifactTypeDefinition{}, nil
	}

	roots, err := artifactTypeRootsForLibraryPath(workingDir, cfg.Library.Path)
	if err != nil {
		return nil, err
	}

	seen := make(map[string]struct{})
	out := make([]*ArtifactTypeDefinition, 0)
	for _, root := range roots {
		index, err := artifactTypeLoader.Load(root)
		if err != nil {
			return nil, fmt.Errorf("loading artifact types from %s: %w", root, err)
		}
		for _, typ := range index.Types {
			if typ.Prefix != prefix {
				continue
			}
			key := typ.Plugin + "\x00" + typ.TypeID + "\x00" + typ.SourceMetaPath
			if _, ok := seen[key]; ok {
				continue
			}
			defn, err := buildArtifactTypeDefinition(root, typ)
			if err != nil {
				return nil, err
			}
			seen[key] = struct{}{}
			out = append(out, defn)
		}
	}

	sort.Slice(out, func(i, j int) bool {
		if out[i].Plugin != out[j].Plugin {
			return out[i].Plugin < out[j].Plugin
		}
		if out[i].TypeID != out[j].TypeID {
			return out[i].TypeID < out[j].TypeID
		}
		return out[i].SourceMetaPath < out[j].SourceMetaPath
	})

	return out, nil
}

func attachArtifactTypeDefinitions(workingDir string, artifact *Artifact) error {
	defs, err := artifactTypeDefinitionsForPath(workingDir, artifact.Path)
	if err != nil {
		return err
	}
	artifact.TypeDefinitions = defs
	return nil
}

func attachArtifactTypeDefinitionsToArtifacts(workingDir string, artifacts []*Artifact) error {
	for _, artifact := range artifacts {
		if artifact == nil {
			continue
		}
		if err := attachArtifactTypeDefinitions(workingDir, artifact); err != nil {
			return err
		}
	}
	return nil
}

func artifactTypeRootsForLibraryPath(workingDir, libraryPath string) ([]string, error) {
	libPath := libraryPath
	if !filepath.IsAbs(libPath) {
		libPath = filepath.Join(workingDir, libPath)
	}

	roots := []string{libPath}
	parent := filepath.Dir(libPath)
	if filepath.Base(parent) == "plugins" {
		entries, err := os.ReadDir(parent)
		if err != nil {
			if os.IsNotExist(err) {
				return []string{libPath}, nil
			}
			return nil, fmt.Errorf("reading plugin root directory %s: %w", parent, err)
		}
		for _, entry := range entries {
			if entry.IsDir() {
				roots = append(roots, filepath.Join(parent, entry.Name()))
			}
		}
	}

	return dedupeArtifactTypeRoots(roots), nil
}

func dedupeArtifactTypeRoots(roots []string) []string {
	if len(roots) == 0 {
		return nil
	}
	seen := make(map[string]struct{}, len(roots))
	out := make([]string, 0, len(roots))
	for _, root := range roots {
		if root == "" {
			continue
		}
		cleaned := filepath.Clean(root)
		if _, ok := seen[cleaned]; ok {
			continue
		}
		seen[cleaned] = struct{}{}
		out = append(out, cleaned)
	}
	return out
}

func buildArtifactTypeDefinition(root string, typ artifacttypes.Type) (*ArtifactTypeDefinition, error) {
	template, err := loadArtifactTypeDefinitionFile(root, typ.TemplatePath, true)
	if err != nil {
		return nil, fmt.Errorf("%s: template: %w", typ.SourceMetaPath, err)
	}
	prompt, err := loadArtifactTypeDefinitionFile(root, typ.PromptPath, true)
	if err != nil {
		return nil, fmt.Errorf("%s: prompt: %w", typ.SourceMetaPath, err)
	}

	examples := make([]*ArtifactTypeDefinitionExample, 0, len(typ.Examples))
	for _, ex := range typ.Examples {
		example, err := loadArtifactTypeDefinitionExample(root, ex)
		if err != nil {
			return nil, fmt.Errorf("%s: example %s: %w", typ.SourceMetaPath, ex.Path, err)
		}
		if example != nil {
			examples = append(examples, example)
		}
	}

	return &ArtifactTypeDefinition{
		Plugin:         typ.Plugin,
		TypeID:         typ.TypeID,
		Name:           typ.Name,
		Description:    typ.Description,
		Prefix:         typ.Prefix,
		Pattern:        typ.Pattern,
		Phase:          typ.Phase,
		SourceMetaPath: typ.SourceMetaPath,
		Template:       template,
		Prompt:         prompt,
		Examples:       examples,
	}, nil
}

func loadArtifactTypeDefinitionFile(root, relPath string, required bool) (*ArtifactTypeDefinitionFile, error) {
	relPath = strings.TrimSpace(relPath)
	if relPath == "" {
		if required {
			return nil, fmt.Errorf("missing file path")
		}
		return nil, nil
	}

	absPath := filepath.Join(root, filepath.FromSlash(relPath))
	content, truncated, originalBytes, err := evidence.ReadFileClamped(absPath, artifactTypeFileCapBytes)
	if err != nil {
		if required {
			return nil, err
		}
		return nil, nil
	}
	inline := string(content)
	return &ArtifactTypeDefinitionFile{
		Path:        filepath.ToSlash(relPath),
		Content:     inline,
		IsTruncated: truncated,
		SizeBytes:   int(originalBytes),
	}, nil
}

func loadArtifactTypeDefinitionExample(root string, ex artifacttypes.Example) (*ArtifactTypeDefinitionExample, error) {
	file, err := loadArtifactTypeDefinitionFile(root, ex.Path, false)
	if err != nil || file == nil {
		return nil, err
	}
	desc := ex.Description
	return &ArtifactTypeDefinitionExample{
		Path:        file.Path,
		Description: &desc,
		Content:     file.Content,
		IsTruncated: file.IsTruncated,
		SizeBytes:   file.SizeBytes,
	}, nil
}

// prefixOf returns the first path segment, matching the frontend grouping helper.
func prefixOf(path string) string {
	trimmed := strings.TrimSpace(filepath.ToSlash(path))
	trimmed = strings.TrimPrefix(trimmed, "/")
	if trimmed == "" {
		return ""
	}
	if idx := strings.IndexByte(trimmed, '/'); idx >= 0 {
		return trimmed[:idx]
	}
	return trimmed
}

